import React from 'react';
import { useOSStore, Theme } from '@/store/osStore';
import { useI18nStore } from '@/store/i18nStore';
import { Settings, Palette, Type, Maximize } from 'lucide-react';

export function SettingsModule() {
    const { theme, setTheme, fontSize, setFontSize, fontFamily, setFontFamily } = useOSStore();
    const { t } = useI18nStore();

    const themes: { id: Theme; label: string; color: string }[] = [
        { id: 'dark', label: 'Dark Mode', color: '#0f172a' },
        { id: 'light', label: 'Light Mode', color: '#f8fafc' },
        { id: 'sea', label: 'Deep Sea', color: '#0c4a6e' },
        { id: 'sky', label: 'Airy Sky', color: '#e0f2fe' },
        { id: 'paper', label: 'Blueprint', color: '#fdfbf7' },
    ];

    const fontFamilies = [
        { id: 'sans', label: 'Sans Serif (Inter)', sample: 'Aa' },
        { id: 'mono', label: 'Monospace (JetBrains)', sample: 'Aa' },
        { id: 'serif', label: 'Serif (Georgia)', sample: 'Aa' },
    ] as const;

    const fontSizes = [
        { id: 'small', label: 'Small', size: '12px' },
        { id: 'medium', label: 'Medium', size: '14px' },
        { id: 'large', label: 'Large', size: '16px' },
    ] as const;

    return (
        <div className="flex flex-col h-full bg-[#0a0e14]/95 text-slate-300 font-sans overflow-y-auto custom-scrollbar p-6">
            <div className="max-w-3xl mx-auto w-full space-y-8">

                {/* Header */}
                <div className="flex items-center gap-3 pb-4 border-b border-white/10">
                    <div className="p-2 bg-cyan-500/10 text-cyan-400 rounded-lg">
                        <Settings size={24} />
                    </div>
                    <div>
                        <h1 className="text-xl font-bold text-white tracking-wide">OS Settings</h1>
                        <p className="text-sm text-slate-500">Customize appearance, typography, and system preferences.</p>
                    </div>
                </div>

                {/* Theme Section */}
                <section className="space-y-4">
                    <div className="flex items-center gap-2 text-white">
                        <Palette size={18} className="text-cyan-400" />
                        <h2 className="text-lg font-semibold">Theme Colors</h2>
                    </div>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                        {themes.map(tOption => (
                            <button
                                key={tOption.id}
                                onClick={() => setTheme(tOption.id)}
                                className={`flex flex-col items-center gap-3 p-4 rounded-xl border transition-all ${theme === tOption.id
                                        ? 'border-cyan-500 bg-cyan-500/10 shadow-[0_0_15px_rgba(6,182,212,0.15)]'
                                        : 'border-white/10 bg-white/5 hover:border-white/20 hover:bg-white/10'
                                    }`}
                            >
                                <div
                                    className="w-12 h-12 rounded-full border-2 border-white/20 shadow-inner"
                                    style={{ backgroundColor: tOption.color }}
                                />
                                <span className={`text-sm font-medium ${theme === tOption.id ? 'text-cyan-400' : 'text-slate-300'}`}>
                                    {tOption.label}
                                </span>
                            </button>
                        ))}
                    </div>
                </section>

                {/* Typography Section */}
                <section className="space-y-4 pt-4 border-t border-white/5">
                    <div className="flex items-center gap-2 text-white">
                        <Type size={18} className="text-blue-400" />
                        <h2 className="text-lg font-semibold">Typography Family</h2>
                    </div>
                    <div className="grid grid-cols-3 gap-4">
                        {fontFamilies.map(font => (
                            <button
                                key={font.id}
                                onClick={() => setFontFamily(font.id)}
                                className={`flex items-center justify-between p-4 rounded-xl border transition-all ${fontFamily === font.id
                                        ? 'border-blue-500 bg-blue-500/10'
                                        : 'border-white/10 bg-white/5 hover:bg-white/10 hover:border-white/20'
                                    }`}
                            >
                                <span className={`text-sm font-medium ${fontFamily === font.id ? 'text-blue-400' : 'text-slate-300'}`}>
                                    {font.label}
                                </span>
                                <span className="text-2xl font-black text-white/50" style={{ fontFamily: font.id === 'mono' ? 'var(--font-jetbrains-mono)' : font.id === 'serif' ? 'Georgia, serif' : 'var(--font-inter)' }}>
                                    {font.sample}
                                </span>
                            </button>
                        ))}
                    </div>
                </section>

                {/* Font Size Section */}
                <section className="space-y-4 pt-4 border-t border-white/5 pb-8">
                    <div className="flex items-center gap-2 text-white">
                        <Maximize size={18} className="text-emerald-400" />
                        <h2 className="text-lg font-semibold">Interface Scaling (Font Size)</h2>
                    </div>
                    <div className="grid grid-cols-3 gap-4">
                        {fontSizes.map(size => (
                            <button
                                key={size.id}
                                onClick={() => setFontSize(size.id)}
                                className={`flex flex-col items-center justify-center p-4 rounded-xl border transition-all min-h-[80px] ${fontSize === size.id
                                        ? 'border-emerald-500 bg-emerald-500/10'
                                        : 'border-white/10 bg-white/5 hover:bg-white/10 hover:border-white/20'
                                    }`}
                            >
                                <span className="text-white font-medium mb-1" style={{ fontSize: size.size }}>
                                    Aa
                                </span>
                                <span className={`text-xs ${fontSize === size.id ? 'text-emerald-400' : 'text-slate-500'}`}>
                                    {size.label} ({size.size})
                                </span>
                            </button>
                        ))}
                    </div>
                </section>

            </div>
        </div>
    );
}

export default SettingsModule;
